// ── RHUM32 TABLE GRID ────────────────────────────────
function buildRhum32Grid(gridId) {
  const grid=document.getElementById(gridId); if (!grid) return;
  const bank=getBank(); grid.innerHTML='';
  Object.values(RHUM32_TABLES).forEach(t => {
    const ok=bank>=t.minBank;
    const vipLabel = t.minBet===10000 ? 'VIP ' : '';
    const d=document.createElement('div');
    d.className='tc'+(ok?'':' locked');
    d.innerHTML=`<div class="tc-bet">${vipLabel}$${t.minBet.toLocaleString()}</div>
      <div class="tc-name">Rhum32 Table</div>
      <div>
        <div class="tc-row"><span class="tc-l">Min Bank Required</span><span class="tc-r">$${t.minBank.toLocaleString()}</span></div>
        <div class="tc-row"><span class="tc-l">Wallet Size</span><span class="tc-r gold">$${t.wallet.toLocaleString()}</span></div>
        <div class="tc-row"><span class="tc-l">Max Front Bet</span><span class="tc-r">$${t.maxBet.toLocaleString()}</span></div>
        <div class="tc-row"><span class="tc-l">Tie Bet</span><span class="tc-r">${t.tieBetMin===0?'No Limit':'$'+t.tieBetMin.toLocaleString()+' – $'+t.tieBetMax.toLocaleString()}</span></div>
      </div>
      <div style="margin-top:14px">
        ${ok?`<button class="btn bp bsm bfull" onclick="enterRhum32Table(${t.minBet})">Enter Table →</button>`
            :`<div style="font-size:11px;color:var(--text-dim)">Need $${t.minBank.toLocaleString()} in bank</div>`}
      </div>`;
    grid.appendChild(d);
  });
}

