let pendingGameType = 'sipsam'; // track which game we're entering

function enterTable(minBet) {
  pendingTable=TABLES[Number(minBet)];
  pendingGameType='sipsam';
  if (!pendingTable) return;
  runAd('pregame',10,'⚡ Quick Ad Break','Watch a short ad to enter the table. Your seat is reserved.');
}

function enterRhum32Table(minBet) {
  pendingTable=RHUM32_TABLES[Number(minBet)];
  pendingGameType='rhum32';
  if (!pendingTable) return;
  runAd('pregame',10,'⚡ Quick Ad Break','Watch a short ad to enter the Rhum32 table. Your seat is reserved.');
}

function cancelPregame() { stopAd(); pendingTable=null; pendingGameType='sipsam'; }

async function confirmEnter() {
  stopAd();
  document.getElementById('mo-pregame').classList.remove('show');

  const gameType = pendingGameType || 'sipsam';
  const storagePrefix = gameType === 'rhum32' ? 'rhum32' : 'sipsam';

  // Set sessionStorage FIRST — before any API calls that might fail
  sessionStorage.setItem(storagePrefix+'_table',  JSON.stringify(pendingTable));
  sessionStorage.setItem(storagePrefix+'_wallet', String(pendingTable.wallet || pendingTable.walletSize || 0));
  sessionStorage.setItem(storagePrefix+'_user',   JSON.stringify({
    id:       currentUser.id       || currentUser.user_id || 0,
    username: currentUser.username,
    token:    authToken || ''
  }));

  // Deduct wallet from bank locally so UI updates immediately
  const walletAmt = pendingTable.wallet || pendingTable.walletSize || 0;
  const newBank   = (currentUser.bankBalance || currentUser.bank_balance || 0) - walletAmt;
  currentUser.bankBalance   = newBank;
  currentUser.bank_balance  = newBank;
  refreshUI();

  // Try to record entry on server — but don't block redirect if it fails
  const enterEndpoint = gameType === 'rhum32' ? '/api/game/rhum32/enter' : '/api/game/enter';
  try {
    await apiPost('/api/game/media/watch', {adType:'pregame'});
    await apiPost(enterEndpoint, {tableMinBet: pendingTable.minBet});
  } catch(e) {
    console.warn('[VurgLife] Enter API call failed — continuing anyway:', e);
  }

  // Redirect to game
  window.location.href = gameType === 'rhum32' ? '/rhum32' : '/sipsam';
}

