        ${rec?'<div style="font-size:9px;font-weight:700;color:var(--gold);background:rgba(201,168,76,.12);border:1px solid rgba(201,168,76,.25);padding:2px 7px;border-radius:8px;letter-spacing:1px">RECOMMENDED</div>':''}
      </div>
      <div class="tc-bet">$${t.minBet.toLocaleString()}</div>
      <div class="tc-name">${t.label} Table</div>
      <div>
        <div class="tc-row"><span class="tc-l">Min Bank Required</span><span class="tc-r">$${t.minBank.toLocaleString()}</span></div>
        <div class="tc-row"><span class="tc-l">Wallet Size</span><span class="tc-r gold">$${t.wallet.toLocaleString()}</span></div>
        <div class="tc-row"><span class="tc-l">Big Blind</span><span class="tc-r">$${t.minBet.toLocaleString()}</span></div>
