async function searchFriend() {
  const q=document.getElementById('friend-q').value.trim(); if (!q) return;
  const el=document.getElementById('friend-results');
  el.innerHTML='<div style="color:var(--text-dim);font-size:13px">Searching...</div>';
  try {
    const r=await fetch('/api/friends/search',{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+authToken},body:JSON.stringify({query:q})});
    const d=await r.json();
    if (!d.ok||!d.users?.length) { el.innerHTML='<div style="color:var(--text-dim);font-size:13px">No users found.</div>'; return; }
    el.innerHTML=d.users.map(u=>`<div style="display:flex;align-items:center;justify-content:space-between;padding:8px 0;border-bottom:1px solid var(--border)">
      <span style="color:var(--text)">${esc(u.username)}</span>
      ${u.isFriend?'<span style="color:var(--gold);font-size:12px">Already friends</span>':'<button class="btn bp bsm" onclick="sendFriendRequest('+u.id+',this)">Add Friend</button>'}
    </div>`).join('');
  } catch(e) { el.innerHTML='<div style="color:#f55;font-size:13px">Error searching.</div>'; }
}
async function sendFriendRequest(userId,btn) {
  btn.disabled=true; btn.textContent='Sending...';
  try {
    const r=await fetch('/api/friends/request',{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+authToken},body:JSON.stringify({targetUserId:userId})});
    const d=await r.json();
    btn.textContent=d.ok?'Sent!':d.error||'Failed';
  } catch(e) { btn.textContent='Error'; }
}
async function loadFriends() {
  const el=document.getElementById('friends-list');
  try {
    const r=await fetch('/api/friends',{headers:{'Authorization':'Bearer '+authToken}});
    const d=await r.json();
    if (!d.ok||!d.friends?.length) { el.innerHTML='<div style="color:var(--text-dim);font-size:13px;padding:10px 0">No friends added yet.</div>'; return; }
    el.innerHTML=d.friends.map(f=>`<div style="display:flex;align-items:center;justify-content:space-between;padding:8px 0;border-bottom:1px solid var(--border)">
      <span style="color:var(--text)">${esc(f.username)}</span>
      <div style="display:flex;gap:6px">
        <button class="btn bgh bsm" onclick="removeFriend(${f.id},this)" title="Remove">✕</button>
      </div>
    </div>`).join('');
  } catch(e) { el.innerHTML='<div style="color:#f55;font-size:13px">Error loading friends.</div>'; }
}
async function loadPendingRequests() {
  const el=document.getElementById('friend-reqs');
  try {
    const r=await fetch('/api/friends/pending',{headers:{'Authorization':'Bearer '+authToken}});
    const d=await r.json();
    if (!d.ok||!d.pending?.length) { el.innerHTML='<div style="color:var(--text-dim);font-size:13px;padding:10px 0">No pending requests.</div>'; return; }
    el.innerHTML=d.pending.map(p=>`<div style="display:flex;align-items:center;justify-content:space-between;padding:8px 0;border-bottom:1px solid var(--border)">
      <span style="color:var(--text)">${esc(p.from_username)}</span>
      <div style="display:flex;gap:6px">
        <button class="btn bp bsm" onclick="acceptFriendReq(${p.from_id},this)">Accept</button>
        <button class="btn bgh bsm" onclick="rejectFriendReq(${p.from_id},this)">Reject</button>
      </div>
    </div>`).join('');
  } catch(e) { el.innerHTML='<div style="color:#f55;font-size:13px">Error loading requests.</div>'; }
}
async function acceptFriendReq(fromId,btn) {
  btn.disabled=true;
  await fetch('/api/friends/accept',{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+authToken},body:JSON.stringify({fromUserId:fromId})});
  loadFriends(); loadPendingRequests();
}
