// ── GAME INVITE POLLING ───────────────────────────────
let _seenInvites = new Set();
let _invitePollTimer = null;

function startInvitePolling() {
  if (_invitePollTimer) return;
  _invitePollTimer = setInterval(pollInvites, 5000);
  pollInvites(); // first check immediately
}

function stopInvitePolling() {
  if (_invitePollTimer) { clearInterval(_invitePollTimer); _invitePollTimer = null; }
}

async function pollInvites() {
  if (!authToken && !currentUser) return;
  try {
    const res = await apiGet('/api/friends/invites');
    if (!res?.ok || !res.invites?.length) return;
    res.invites.forEach(inv => {
      if (_seenInvites.has(inv.inviteId)) return;
      _seenInvites.add(inv.inviteId);
      showInvitePopup(inv);
    });
  } catch(e) {}
}

function showInvitePopup(inv) {
  const existing = document.getElementById('invite-popup-' + inv.inviteId);
  if (existing) return;
  const gameNames = {sipsam:'SipSam',rhum32:'Rhum 32',blackjack:'Blackjack',holdem:"Hold'em"};
  const gameName = gameNames[inv.game] || inv.game;
  const el = document.createElement('div');
  el.id = 'invite-popup-' + inv.inviteId;
  el.style.cssText = 'position:fixed;top:20px;right:20px;z-index:99999;background:linear-gradient(135deg,#0d1a2a,#1a2a3a);border:2px solid var(--gold,#c9a84c);border-radius:14px;padding:18px 22px;max-width:340px;box-shadow:0 8px 32px rgba(0,0,0,0.6),0 0 20px rgba(201,168,76,0.2);animation:slideInRight 0.3s ease-out;font-family:sans-serif;color:#e8dfc0';
  const secs = Math.max(0, Math.round((inv.expiresAt - Date.now()) / 1000));
  el.innerHTML = `
    <div style="font-size:11px;color:#8a9a7a;margin-bottom:6px">GAME INVITE</div>
    <div style="font-size:15px;font-weight:700;margin-bottom:4px">${inv.fromUsername} invited you!</div>
    <div style="font-size:13px;color:#a0b090;margin-bottom:12px">${gameName} &mdash; $${inv.tableMinBet} table &bull; Expires in ${Math.floor(secs/60)}:${String(secs%60).padStart(2,'0')}</div>
    <div style="display:flex;gap:8px">
      <button onclick="acceptGameInvite('${inv.inviteId}','${inv.game}',${inv.tableMinBet})" style="flex:1;padding:8px;border:none;border-radius:8px;background:linear-gradient(135deg,#8B6914,#c9a84c);color:#1a1000;font-weight:700;font-size:13px;cursor:pointer">Join Game</button>
      <button onclick="dismissInvite('${inv.inviteId}')" style="padding:8px 14px;border:1px solid rgba(255,255,255,0.15);border-radius:8px;background:transparent;color:#999;font-size:13px;cursor:pointer">Dismiss</button>
    </div>`;
  document.body.appendChild(el);
  // Auto-dismiss after expiry
  setTimeout(() => dismissInvite(inv.inviteId), secs * 1000);
}

function dismissInvite(inviteId) {
  const el = document.getElementById('invite-popup-' + inviteId);
  if (el) el.remove();
}

async function acceptGameInvite(inviteId, game, tableMinBet) {
  dismissInvite(inviteId);
  try {
    const res = await apiPost('/api/friends/invite/accept', { inviteId });
    if (!res?.ok) { toast('Invite Error', res?.error || 'Could not accept invite'); return; }
    // Navigate to the game
    const roomId = res.roomId || null;
    if (game === 'rhum32') {
      const tbl = RHUM32_TABLES[tableMinBet] || RHUM32_TABLES[100];
      sessionStorage.setItem('rhum32_table', JSON.stringify({...tbl, roomId}));
      sessionStorage.setItem('rhum32_user', JSON.stringify({
        id: currentUser.id || currentUser.user_id || 0,
        username: currentUser.username,
        token: authToken || ''
      }));
      window.location.href = '/rhum32';
    } else if (game === 'sipsam') {
      const tbl = TABLES[tableMinBet] || TABLES[100];
      sessionStorage.setItem('sipsam_table', JSON.stringify({...tbl, roomId}));
      sessionStorage.setItem('sipsam_user', JSON.stringify({
        id: currentUser.id || currentUser.user_id || 0,
        username: currentUser.username,
        token: authToken || ''
      }));
      window.location.href = '/sipsam';
    } else if (game === 'blackjack') {
      window.location.href = '/blackjack';
    } else if (game === 'holdem') {
      window.location.href = '/holdem';
    }
  } catch(e) { toast('Error', 'Failed to accept invite'); }
}

