async function enterRouletteTable(minBet) {
  const t=ROULETTE_TABLES[Number(minBet)];
  if (!t) return;
  const bank=getBank();
  if (bank<t.minBank) { toast('Insufficient Balance',`You need $${t.minBank.toLocaleString()} in your bank to enter this table.`); return; }

  // Deduct wallet from bank on the platform
  try {
    const res = await apiPost('/api/game/roulette/enter', { tableMinBet: minBet });
    if (res.error) { toast('⚠️ Error', res.error); return; }
    if (res.newBankBalance != null) {
      currentUser.bankBalance  = res.newBankBalance;
      currentUser.bank_balance = res.newBankBalance;
      refreshUI();
    }
  } catch(e) {
    console.warn('[Roulette enter] platform call failed — continuing anyway:', e);
  }

  sessionStorage.setItem('roulette_table', JSON.stringify({...t, minBet}));
  sessionStorage.setItem('roulette_user', JSON.stringify({
    id: currentUser.id||currentUser.user_id||0,
    username: currentUser.username,
    token: authToken||'',
    avatar: currentUser.avatarPreset||currentUser.avatar_preset||'',
    bankBalance: currentUser.bankBalance||currentUser.bank_balance||0,
  }));

  // Pass handoff via URL so the roulette client picks it up directly.
  const params = new URLSearchParams({
    minBet:   String(t.minBet),
    wallet:   String(t.wallet),
    username: currentUser.username,
    userId:   String(currentUser.id||currentUser.user_id||0),
  });
  window.location.href='/roulette/?' + params.toString();
}
